import React from 'react';
import * as C from './style';
/* import {
    FaRegArrowAltCircleUp,
    FaRegArrowAltCircleDown,
    FaTrash,
} from 'react-icons/fa'; */

function BoxPedido({ pedido }) {
    //console.log(pedido);

    var newCarrinho = JSON.parse(
        `{
            "carnes":1,
            "pontoCarne":"",
            "opcao":1,
            "qtd":3,
            "adc":["","","","",""]
        }`
    )
    pedido.carrinho = newCarrinho

    console.log(newCarrinho);
    return (
        <C.Item>
            <C.Nome>
                <C.PontoCarne>
                    <p>
                        {pedido.pontoCarne}
                    </p>
                </C.PontoCarne>
                <p>
                    {pedido.qtd}{pedido.carnes >= 2 ? 'x'+pedido.carnes : ''} {pedido.nome}
                </p>
            </C.Nome>
            <C.BoxAdc qtdAdc={pedido.adc.length}>
                {pedido.adc.map( (e, index) => (
                    <C.Adc key={index}>{'+' + e}</C.Adc>
                ))}
            </C.BoxAdc>
            <C.Obs>
                <p>{pedido.obs}</p>
            </C.Obs>
        </C.Item>
    )
}

export default BoxPedido
